// Falha intencional para disparar o errorWorkflow configurado.
// n8n preserva apenas {level,tags,description,lineNumber,message,stack} do
// Error no payload do errorTrigger. Por isso embutimos o test_run_id na
// mensagem — o errorWorkflow (IGOR_07) o captura via error.message e o
// harness filtra os asserts por LIKE '%test_run_id%'.
const body = $input.first().json.body || {};
const trid = body.test_run_id || 'none';
throw new Error('IGOR canary simulated failure (test_run_id=' + trid + ')');
